// Zero-AI geolocation helpers: read a photo's EXIF GPS + timestamp, match it to
// the nearest FEHD district, and group a batch of photos into "meals" by
// time + GPS proximity. Pure metadata + arithmetic — no AI, no network, no vendor.
//
// NOTE: FEHD's open feed has district but no per-restaurant coordinates, so we
// match to the nearest DISTRICT (~20 centroids below) and narrow the pick to it.
// Exact per-restaurant matching would need the CSDI spatial layer (API-key gated)
// — a vendor decision to raise later.

export interface PhotoMeta {
  lat?: number;
  lng?: number;
  time?: number; // epoch ms (EXIF DateTimeOriginal, else file lastModified)
}

// Approximate district centroids, keyed by the `area` names in the catalogue.
const DISTRICT_CENTROIDS: Record<string, [number, number]> = {
  Eastern: [22.283, 114.222], "Wan Chai": [22.277, 114.173], Southern: [22.247, 114.16],
  Islands: [22.289, 113.941], "Central/Western": [22.283, 114.154],
  "Kwun Tong": [22.312, 114.226], "Kowloon City": [22.328, 114.183],
  "Wong Tai Sin": [22.342, 114.194], "Yau Tsim": [22.305, 114.171],
  "Mong Kok": [22.319, 114.169], "Sham Shui Po": [22.33, 114.162],
  "Kwai Tsing": [22.357, 114.131], "Tsuen Wan": [22.371, 114.114],
  "Tuen Mun": [22.391, 113.973], "Yuen Long": [22.443, 114.022],
  "Tai Po": [22.451, 114.164], North: [22.502, 114.128], "Sha Tin": [22.383, 114.198],
  "Sai Kung": [22.381, 114.271], "Food Truck": [22.3, 114.17],
};

const R = 6371e3; // earth radius (m)
export function haversine(a: [number, number], b: [number, number]): number {
  const toRad = (d: number) => (d * Math.PI) / 180;
  const dLat = toRad(b[0] - a[0]);
  const dLng = toRad(b[1] - a[1]);
  const s =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(a[0])) * Math.cos(toRad(b[0])) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(s));
}

/** Nearest FEHD district (area name) to a coordinate, or null if out of range. */
export function nearestArea(lat: number, lng: number): string | null {
  let best: string | null = null;
  let bestD = Infinity;
  for (const [area, c] of Object.entries(DISTRICT_CENTROIDS)) {
    const d = haversine([lat, lng], c);
    if (d < bestD) { bestD = d; best = area; }
  }
  // > ~40km from every HK district centroid → treat as no match.
  return bestD <= 40_000 ? best : null;
}

// ---- EXIF (GPS + DateTimeOriginal) -----------------------------------------

/** Parse EXIF GPS + timestamp from a JPEG file. Returns {} when absent. */
export async function readPhotoMeta(file: File): Promise<PhotoMeta> {
  const fallback: PhotoMeta = { time: file.lastModified || undefined };
  try {
    const buf = await file.arrayBuffer();
    const meta = parseExif(new DataView(buf));
    return {
      lat: meta.lat,
      lng: meta.lng,
      time: meta.time ?? fallback.time,
    };
  } catch {
    return fallback;
  }
}

function parseExif(dv: DataView): PhotoMeta {
  if (dv.getUint16(0) !== 0xffd8) return {}; // not JPEG
  let offset = 2;
  while (offset + 4 < dv.byteLength) {
    const marker = dv.getUint16(offset);
    const size = dv.getUint16(offset + 2);
    if (marker === 0xffe1) {
      // APP1 — check "Exif\0\0"
      if (dv.getUint32(offset + 4) === 0x45786966) {
        return parseTiff(dv, offset + 10);
      }
    }
    if ((marker & 0xff00) !== 0xff00) break;
    offset += 2 + size;
  }
  return {};
}

function parseTiff(dv: DataView, tiff: number): PhotoMeta {
  const le = dv.getUint16(tiff) === 0x4949; // II = little-endian
  const u16 = (o: number) => dv.getUint16(o, le);
  const u32 = (o: number) => dv.getUint32(o, le);

  const ifd0 = tiff + u32(tiff + 4);
  let gpsIfd = 0;
  let exifIfd = 0;
  const n0 = u16(ifd0);
  for (let i = 0; i < n0; i++) {
    const e = ifd0 + 2 + i * 12;
    const tag = u16(e);
    if (tag === 0x8825) gpsIfd = tiff + u32(e + 8);
    if (tag === 0x8769) exifIfd = tiff + u32(e + 8);
  }

  const out: PhotoMeta = {};

  if (exifIfd) {
    const n = u16(exifIfd);
    for (let i = 0; i < n; i++) {
      const e = exifIfd + 2 + i * 12;
      if (u16(e) === 0x9003) {
        // DateTimeOriginal ASCII "YYYY:MM:DD HH:MM:SS"
        const cnt = u32(e + 4);
        const vo = cnt > 4 ? tiff + u32(e + 8) : e + 8;
        let s = "";
        for (let k = 0; k < cnt - 1; k++) s += String.fromCharCode(dv.getUint8(vo + k));
        const m = /^(\d{4}):(\d{2}):(\d{2}) (\d{2}):(\d{2}):(\d{2})/.exec(s);
        if (m) out.time = new Date(+m[1], +m[2] - 1, +m[3], +m[4], +m[5], +m[6]).getTime();
      }
    }
  }

  if (gpsIfd) {
    let latRef = "N";
    let lngRef = "E";
    let lat: number[] | null = null;
    let lng: number[] | null = null;
    const rational = (o: number) => u32(o) / (u32(o + 4) || 1);
    const readDMS = (e: number): number[] => {
      const vo = tiff + u32(e + 8); // 3 rationals = 24 bytes → always offset
      return [rational(vo), rational(vo + 8), rational(vo + 16)];
    };
    const n = u16(gpsIfd);
    for (let i = 0; i < n; i++) {
      const e = gpsIfd + 2 + i * 12;
      const tag = u16(e);
      if (tag === 0x0001) latRef = String.fromCharCode(dv.getUint8(e + 8));
      if (tag === 0x0002) lat = readDMS(e);
      if (tag === 0x0003) lngRef = String.fromCharCode(dv.getUint8(e + 8));
      if (tag === 0x0004) lng = readDMS(e);
    }
    if (lat && lng) {
      const dec = (d: number[]) => d[0] + d[1] / 60 + d[2] / 3600;
      out.lat = dec(lat) * (latRef === "S" ? -1 : 1);
      out.lng = dec(lng) * (lngRef === "W" ? -1 : 1);
    }
  }
  return out;
}

// ---- grouping into "meals" -------------------------------------------------

export interface PhotoGroup {
  indices: number[]; // indices into the original file list
  time?: number; // representative (earliest) time, if known
  lat?: number;
  lng?: number;
}

/**
 * Group photos into meals: a new group starts when the time gap exceeds
 * `gapMs` (default 2h) OR the GPS distance from the group exceeds `gapM`
 * (default 300m). Photos without time keep their input order.
 */
export function groupPhotos(
  metas: PhotoMeta[],
  gapMs = 2 * 3600_000,
  gapM = 300
): PhotoGroup[] {
  const order = metas
    .map((m, i) => ({ m, i }))
    .sort((a, b) => (a.m.time ?? 0) - (b.m.time ?? 0));

  const groups: PhotoGroup[] = [];
  for (const { m, i } of order) {
    const g = groups[groups.length - 1];
    const farTime =
      g && m.time != null && g.time != null && Math.abs(m.time - g.time) > gapMs;
    const farGeo =
      g && m.lat != null && g.lat != null &&
      haversine([m.lat, m.lng!], [g.lat, g.lng!]) > gapM;
    if (!g || farTime || farGeo) {
      groups.push({ indices: [i], time: m.time, lat: m.lat, lng: m.lng });
    } else {
      g.indices.push(i);
      if (g.lat == null && m.lat != null) { g.lat = m.lat; g.lng = m.lng; }
    }
  }
  return groups;
}
