// Taste profile + FEHD candidate filtering for "未去過" suggestions. All FREE and
// on-device (§4b: derived from the user's own memories; nothing leaves here).
import type { Catalogue, Memory, Restaurant } from "./types";

// Taste tag → distinctive FEHD restaurant-name keywords + INFO facility codes.
// Keywords are curated to be DISTINCTIVE (no generic 餐廳/食店) so the filter stays
// tight. INFO codes: G=刺身, H=壽司, F=生蠔.
export const CUISINE_MAP: Record<string, { names: string[]; info: string[] }> = {
  辣: { names: ["辣", "麻辣", "川", "四川", "湘", "雲南", "水煮", "冬蔭", "咖喱", "咖哩"], info: [] },
  米線: { names: ["米線", "米綫", "雲南"], info: [] },
  麵: { names: ["粉麵", "麵家", "麵館", "雲吞麵", "牛腩麵"], info: [] },
  拉麵: { names: ["拉麵", "豚骨", "沾麵"], info: [] },
  壽司: { names: ["壽司", "寿司", "鮨", "板前"], info: ["H"] },
  刺身: { names: ["刺身", "魚生", "割烹"], info: ["G"] },
  日式: { names: ["和食", "居酒屋", "丼", "燒肉", "鐵板燒", "日本料理"], info: ["G", "H"] },
  火鍋: { names: ["火鍋", "打邊爐", "鍋物", "涮", "麻辣燙"], info: [] },
  海鮮: { names: ["海鮮", "漁", "蟹", "蠔", "海產"], info: ["F"] },
  燒味: { names: ["燒臘", "燒味", "燒鵝", "叉燒", "燒肉飯"], info: [] },
  點心: { names: ["點心", "飲茶", "茶樓", "酒家", "酒樓"], info: [] },
  咖啡: { names: ["咖啡", "café", "cafe", "coffee", "咖啡室"], info: [] },
  西式: { names: ["牛扒", "扒房", "意粉", "pasta", "pizza", "薄餅", "bistro", "grill", "steak"], info: [] },
  泰: { names: ["泰", "泰國", "冬蔭", "船河"], info: [] },
  韓: { names: ["韓", "韓國", "韓式", "部隊", "石鍋"], info: [] },
  越南: { names: ["越南", "越式", "河粉", "pho"], info: [] },
  甜品: { names: ["甜品", "糖水", "甜點", "dessert"], info: [] },
  素: { names: ["素食", "齋", "vegan", "蔬食"], info: [] },
  快餐: { names: ["快餐", "漢堡", "炸雞", "burger"], info: [] },
  茶餐廳: { names: ["冰室", "茶冰廳"], info: [] },
};

/** All known cuisine tags — used to compute「未去過類型」(新口味) for diversity. */
export const CUISINE_TAGS = Object.keys(CUISINE_MAP);

export interface TasteProfile {
  liked: string[]; // taste tags, strongest first
  disliked: string[];
  keywords: { kw: string; info: string[]; tag: string }[];
}

/** Derive a taste profile from ALL memories: 👍 lifts a tag, 👎 sinks it. */
export function deriveTasteProfile(memories: Memory[]): TasteProfile {
  const like = new Map<string, number>();
  const dislike = new Map<string, number>();
  for (const m of memories) {
    for (const d of m.dishes) {
      const w = d.rating === "good" ? 2 : d.rating === "bad" ? -2 : 1; // unrated = mild like
      const tags = new Set<string>([...(d.tasteTags || []), ...(m.tasteTags || [])]);
      for (const t of tags) {
        if (w >= 0) like.set(t, (like.get(t) || 0) + w);
        else dislike.set(t, (dislike.get(t) || 0) + -w);
      }
    }
  }
  const liked = [...like.entries()]
    .filter(([t, s]) => s > 0 && (dislike.get(t) || 0) < s)
    .sort((a, b) => b[1] - a[1])
    .map(([t]) => t);
  const disliked = [...dislike.entries()]
    .filter(([t, s]) => s > (like.get(t) || 0))
    .map(([t]) => t);

  return { liked, disliked, keywords: keywordsForTags(liked) };
}

/** Expand taste tags → distinctive FEHD name keywords + INFO codes (deduped). */
export function keywordsForTags(tags: string[]): TasteProfile["keywords"] {
  const out: TasteProfile["keywords"] = [];
  const seen = new Set<string>();
  for (const t of tags) {
    const m = CUISINE_MAP[t];
    if (!m) continue;
    for (const kw of m.names) if (!seen.has(kw)) { seen.add(kw); out.push({ kw, info: m.info, tag: t }); }
  }
  return out;
}

// Extra query-side synonyms (things a user SAYS that aren't distinctive FEHD name
// keywords). Maps to a CUISINE_MAP tag.
const QUERY_SYN: Record<string, string[]> = {
  日式: ["日本", "日料", "日式", "魚生", "放題", "天婦羅", "天麩羅", "壽司", "刺身", "拉麵", "丼"],
  辣: ["川菜", "四川", "湘", "湘菜", "辣嘢", "麻辣"],
  火鍋: ["邊爐", "涮", "鍋"],
  韓: ["韓國", "韓式", "韓燒"],
  泰: ["泰國", "泰式"],
  越南: ["越式"],
  西式: ["西餐", "扒", "牛排", "意大利", "薄餅"],
  點心: ["飲茶", "蝦餃", "燒賣"],
  海鮮: ["魚", "蟹", "蠔"],
  甜品: ["糖水", "甜"],
  咖啡: ["cafe", "café", "coffee"],
};

/** Detect the in-the-moment cuisine/taste condition the user TYPED (e.g.
 *  「想食日本嘢」→ ["日式"]). Used as the priority filter, even if the user has
 *  never logged that taste. Returns CUISINE_MAP tags. */
export function cuisineInQuery(query: string): string[] {
  const q = query.toLowerCase();
  const hits: string[] = [];
  for (const tag of Object.keys(CUISINE_MAP)) {
    const words = [tag, ...CUISINE_MAP[tag].names.map((n) => n.toLowerCase()), ...(QUERY_SYN[tag] || [])];
    if (words.some((w) => w && q.includes(w.toLowerCase()))) hits.push(tag);
  }
  return [...new Set(hits)];
}

/** Best-effort cuisine guess for a restaurant, from its NAME (no supply claims). */
export function restaurantCuisines(r: Restaurant): string[] {
  return cuisineInQuery(`${r.name.tc} ${r.name.en || ""}`);
}

/** Personalisation indicator ("你會幾鍾意") from taste overlap — zero-AI, no spend.
 *  null when we can't tell (no profile, or no cuisine guess). */
export function tasteMatch(r: Restaurant, liked: string[]): { level: "high" | "mid"; cuisines: string[] } | null {
  if (!liked.length) return null;
  const overlap = restaurantCuisines(r).filter((c) => liked.includes(c));
  if (!overlap.length) return null;
  return { level: overlap.length >= 2 ? "high" : "mid", cuisines: [...new Set(overlap)] };
}

export interface Candidate {
  r: Restaurant;
  score: number;
  tag: string; // which taste it matched
}

/** Filter a district's FEHD restaurants by the taste profile → the tightest few
 *  candidates (name-keyword + INFO match; distinctive/longer keywords weigh more).
 *  Excludes already-visited places. Returns AT MOST `limit` (3–5). */
export function filterByTaste(
  cat: Catalogue,
  area: string,
  profile: TasteProfile,
  visited: Set<string>,
  limit = 5
): Candidate[] {
  if (!profile.keywords.length) return [];
  const out: Candidate[] = [];
  for (const r of cat.restaurants) {
    if (r.area !== area || visited.has(r.id)) continue;
    const nm = (r.name.tc || "") + (r.name.en || "").toLowerCase();
    let score = 0;
    let tag = "";
    for (const { kw, info, tag: t } of profile.keywords) {
      if (nm.includes(kw)) { score += Math.max(2, kw.length); tag ||= t; }
      if (info.length && r.info && info.some((c) => r.info!.includes(c))) { score += 2; tag ||= t; }
    }
    if (score > 0) out.push({ r, score, tag });
  }
  out.sort((a, b) => b.score - a.score);
  return out.slice(0, limit);
}

/** HARD diversity quota: at most `maxPerTag` candidates of any one cuisine tag,
 *  up to `limit` total, preserving the incoming (score/round-robin) order. This is
 *  the real散開 pass — round-robin alone still clustered when one tag dominated the
 *  pool. */
export function capByTag(cands: Candidate[], maxPerTag: number, limit: number): Candidate[] {
  const out: Candidate[] = [];
  const count = new Map<string, number>();
  for (const c of cands) {
    const t = c.tag || "_";
    if ((count.get(t) || 0) >= maxPerTag) continue;
    count.set(t, (count.get(t) || 0) + 1);
    out.push(c);
    if (out.length >= limit) break;
  }
  return out;
}

/** Round-robin across matched tags so a multi-cuisine profile yields VARIETY
 *  (辣 · 日式 · 米線…) rather than five 辣 places in a row. */
export function diversify(cands: Candidate[]): Candidate[] {
  const byTag = new Map<string, Candidate[]>();
  for (const c of cands) {
    const t = c.tag || "_";
    if (!byTag.has(t)) byTag.set(t, []);
    byTag.get(t)!.push(c);
  }
  const out: Candidate[] = [];
  let added = true;
  while (added) {
    added = false;
    for (const list of byTag.values()) {
      const c = list.shift();
      if (c) { out.push(c); added = true; }
    }
  }
  return out;
}
