// "未去過" suggestion orchestration (client side).
//  ① own 👍 in the district (free, moat)  ② taste-filter FEHD → tight candidates
//  (free)  ③ Google-check + Haiku synth via /suggest (Phase B)  ④ honest source.
// Cache stores DERIVED facts only (place_id + rating bucket) → same-area re-ask is
// free (template, no Google/Haiku). Falls back to Phase A (names, "未查評價") when
// there's no endpoint or the cap is hit.
import type { Catalogue, Memory, Retrieved } from "./types";
import type { RecallResult, SuggestionItem } from "./recall";
import type { Candidate } from "./taste";
import { areaInQuery, resolveArea } from "./catalogue";
import { deriveTasteProfile, filterByTaste, keywordsForTags, cuisineInQuery, diversify, capByTag, restaurantCuisines, CUISINE_TAGS } from "./taste";
import { getTasteSeed, getHomeAreas } from "./onboarding";

const RECALL = (import.meta.env.VITE_RECALL_ENDPOINT as string | undefined) || "";
const ENDPOINT = RECALL ? RECALL.replace(/\/recall$/, "/suggest") : "";

const CACHE_KEY = "dm.suggestCache";
const TTL = 7 * 86400 * 1000;

interface CachedCand { restaurantId: string; name: string; area: string; tag: string; ratingBucket: string | null; placeId: string }

function cacheGet(key: string): CachedCand[] | null {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    const e = all[key];
    if (e && Date.now() - e.ts < TTL) return e.cands;
  } catch { /* ignore */ }
  return null;
}
function cacheSet(key: string, cands: CachedCand[]): void {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    all[key] = { ts: Date.now(), cands };
    localStorage.setItem(CACHE_KEY, JSON.stringify(all));
  } catch { /* ignore */ }
}

// ---- suggestion feedback (client-only signal: teach the system) --------------
const FB_KEY = "dm.suggestFeedback";
export interface SuggestFeedback { dismissed: string[]; visited: string[] }
export function getSuggestFeedback(): SuggestFeedback {
  try {
    const v = JSON.parse(localStorage.getItem(FB_KEY) || "{}");
    return { dismissed: v.dismissed || [], visited: v.visited || [] };
  } catch {
    return { dismissed: [], visited: [] };
  }
}
export function addSuggestFeedback(kind: "dismissed" | "visited", restaurantId: string): void {
  try {
    const v = getSuggestFeedback();
    if (!v[kind].includes(restaurantId)) v[kind].push(restaurantId);
    localStorage.setItem(FB_KEY, JSON.stringify(v));
  } catch { /* ignore */ }
}

// ---- correction intent (A1 意圖修正 tag → next re-ask reshapes the picks) ------
// The suggestion cards' intent buttons set this; buildSuggestion consumes it once.
export type SuggestIntent =
  | "switch" | "cheap" | "near" | "fresh"      // ordering / area
  | "long-sit" | "no-spicy" | "less-queue" | "no-noodle"; // filter / type bias
let pendingIntent: SuggestIntent | null = null;
export function setSuggestIntent(i: SuggestIntent): void { pendingIntent = i; }
function takeIntent(): SuggestIntent | null { const i = pendingIntent; pendingIntent = null; return i; }

// How each 意圖 reshapes the pool. All zero-API, pure candidate re-shaping.
//  excludeCuisines — drop these cuisine tags entirely (唔好辣 / 唔想食麵).
//  preferType — bias FEHD licence type first (RL 食肆=坐得耐; RR 小食=快/少排隊).
//  leadBucket — which bucket leads the first screen.
//  forceHome — snap to the user's home district (近啲).
interface IntentSpec { excludeCuisines?: string[]; preferType?: "RL" | "RR"; leadBucket?: "fresh" | "quick"; forceHome?: boolean }
function intentSpec(i: SuggestIntent | null): IntentSpec {
  switch (i) {
    case "switch": case "fresh": return { leadBucket: "fresh" };
    case "cheap": return { leadBucket: "quick", preferType: "RR" };
    case "near": return { forceHome: true };
    case "long-sit": return { preferType: "RL" };            // 坐得耐 → sit-down 食肆
    case "less-queue": return { leadBucket: "quick", preferType: "RR" }; // 少排隊 → 小食街坊
    case "no-spicy": return { excludeCuisines: ["辣", "火鍋"] };
    case "no-noodle": return { excludeCuisines: ["麵", "拉麵", "米線"] };
    default: return {};
  }
}

const cName = (c: Candidate): string => c.r.name.tc || c.r.name.en;

// A3 buckets — fixed labels, rendered as headers so the first screen is 3 clear
// picks (熟悉 / 新 / 快穩) instead of 9 same-cuisine cards.
const B_FAMILIAR = "熟悉之選";
const B_FRESH = "新口味";
const B_QUICK = "快速穩陣";

export async function buildSuggestion(
  query: string,
  memories: Memory[],
  cat: Catalogue
): Promise<RecallResult | null> {
  const intent = takeIntent();
  const spec = intentSpec(intent);
  const excludeCuisines = new Set(spec.excludeCuisines || []);

  // Area: from the query, else fall back to the user's home area (onboarding).
  // Home areas are colloquial names (銅鑼灣…) → resolve to the FEHD district.
  // 📍近啲 intent → force the user's own home district even if the query named another.
  const home = getHomeAreas();
  const homeHit = home.length ? { area: resolveArea(home[0]) ?? home[0], name: home[0] } : null;
  const hit = (spec.forceHome && homeHit) ? homeHit : (areaInQuery(query) ?? homeHit);
  if (!hit) return null;

  const baseProfile = deriveTasteProfile(memories);
  const liked = [...new Set([...getTasteSeed(), ...baseProfile.liked])];
  const fb = getSuggestFeedback();
  // Exclude visited + user-dismissed / marked-been-there (teach the system).
  const excluded = new Set([...memories.map((m) => m.restaurantId), ...fb.dismissed, ...fb.visited]);
  // Cuisines the user已經去過/鍾意 → so「新口味」only offers genuinely un-tried types.
  const knownCuisines = new Set<string>([...liked, ...memories.flatMap((m) => cuisineInQuery(m.restaurantName))]);

  // 😋想試新嘢 / 🔄換類型 → break out of any typed cuisine & discover un-tried types.
  const wantFresh = intent === "fresh" || intent === "switch";
  // A typed cuisine that the current intent excludes (e.g.「有咩辣」then「唔好辣」) is
  // dropped → fall through to generic buckets rather than an empty list.
  const queryTags = cuisineInQuery(query).filter((t) => !excludeCuisines.has(t));
  const explicitCuisine = queryTags.length > 0 && !wantFresh; // user asked a specific 菜系

  // ① own record in this district: 👍 first, else onboarding "常去".
  const ownGood = memories.filter((m) => m.area === hit.area && m.dishes.some((d) => d.rating === "good"));
  const ownSeed = memories.filter((m) => m.area === hit.area && m.source === "onboarding" && !ownGood.includes(m));
  const ownCited: Retrieved[] = [...ownGood, ...ownSeed].slice(0, 3).map((m) => ({ memory: m, score: 1, relevance: 1 }));
  const ownLine = ownGood.length
    ? `你喺「${hit.name}」👍 過：${[
        ...new Set(ownGood.flatMap((m) => m.dishes.filter((d) => d.rating === "good").map((d) => `${m.restaurantName}嘅${d.name}`))),
      ].slice(0, 3).join("、")}。`
    : ownSeed.length
      ? `你話你常去「${hit.name}」嘅：${[...new Set(ownSeed.map((m) => m.restaurantName))].slice(0, 3).join("、")}。`
      : "";

  // ② A2 — build a HARD-quota, diversified pool instead of one dominant cuisine.
  //    Generic「食乜好」→ 3 explicit buckets (熟悉 / 新 / 快穩), each capped max 2 of a
  //    cuisine. Explicit「有咩日本嘢」→ honour intent: one capped list of THAT cuisine.
  const taken = new Set<string>(excluded);
  // 唔好辣 / 唔想食麵 → drop any candidate whose name-guessed cuisine is excluded.
  const dropExcluded = (c: Candidate): boolean =>
    !excludeCuisines.size || !restaurantCuisines(c.r).some((x) => excludeCuisines.has(x));
  // preferType (坐得耐 RL / 少排隊·平啲 RR) → stable-bias that licence type to the front.
  const byPreferredType = (cands: Candidate[]): Candidate[] =>
    spec.preferType ? [...cands].sort((a, b) => (b.r.type === spec.preferType ? 1 : 0) - (a.r.type === spec.preferType ? 1 : 0)) : cands;
  const poolFor = (tags: string[], cap: number, n: number): Candidate[] => {
    const eff = tags.filter((t) => !excludeCuisines.has(t));
    const prof = { liked: eff, disliked: baseProfile.disliked, keywords: keywordsForTags(eff) };
    const filtered = byPreferredType(filterByTaste(cat, hit.area, prof, taken, 40).filter(dropExcluded));
    const picked = capByTag(diversify(filtered), cap, n);
    picked.forEach((c) => taken.add(c.r.id)); // no repeats across buckets
    return picked;
  };
  // 快速穩陣: RR (小食) in the area — quick & light, prefer ones matching a known taste.
  // Skip obvious non-food licence holders (夜總會/卡拉OK/酒吧) so the bucket stays appetising.
  const NON_FOOD = /夜總會|卡拉|ktv|karaoke|酒吧|bar\b|club|會所|club house/i;
  const quickPool = (n: number): Candidate[] => {
    const raw: Candidate[] = cat.restaurants
      .filter((r) => r.area === hit.area && r.type === "RR" && !taken.has(r.id) && !NON_FOOD.test(`${r.name.tc || ""} ${r.name.en || ""}`))
      .map((r) => ({ r, score: restaurantCuisines(r).some((c) => knownCuisines.has(c)) ? 2 : 1, tag: restaurantCuisines(r)[0] || "小食" }))
      .filter(dropExcluded)
      .sort((a, b) => b.score - a.score);
    const picked = capByTag(raw, 2, n);
    picked.forEach((c) => taken.add(c.r.id));
    return picked;
  };

  type Bucket = { label: string | null; cands: Candidate[] };
  let buckets: Bucket[];
  if (explicitCuisine) {
    buckets = [{ label: null, cands: poolFor(queryTags, 3, 9) }];
  } else {
    const familiar = liked.length ? poolFor(liked, 2, 3) : [];
    const fresh = poolFor(CUISINE_TAGS.filter((t) => !knownCuisines.has(t)), 2, 3);
    const quick = quickPool(3);
    buckets = [
      { label: B_FAMILIAR, cands: familiar },
      { label: B_FRESH, cands: fresh },
      { label: B_QUICK, cands: quick },
    ];
    // Intent re-orders which bucket leads the first screen.
    if (spec.leadBucket === "fresh") buckets = [buckets[1], buckets[0], buckets[2]]; // 新口味 first
    else if (spec.leadBucket === "quick") buckets = [buckets[2], buckets[0], buckets[1]]; // 快速穩陣 first
    buckets = buckets.filter((b) => b.cands.length);
  }

  // Flatten (priority order) — Google still checks only the top 5 (cost unchanged).
  const flat: { c: Candidate; label: string | null }[] = [];
  for (const b of buckets) for (const c of b.cands) flat.push({ c, label: b.label });
  const candidates = flat.map((f) => f.c);
  if (!ownGood.length && !ownSeed.length && !candidates.length) return null;

  const key = `${hit.area}|${explicitCuisine ? queryTags.slice(0, 4).join(",") : "mix"}`;
  const lead = "幫你揀咗幾款（撳入睇詳情）：";
  const toItem = (c: Candidate, bucket: string | null, rating: string | null = null): SuggestionItem =>
    ({ restaurantId: c.r.id, name: cName(c), area: c.r.area, tag: c.tag, ratingBucket: rating, bucket });
  const result = (items: SuggestionItem[], detail?: string): RecallResult | null => {
    if (!items.length && !ownLine) return null;
    return {
      kind: "recommend",
      cited: ownCited,
      text: [ownLine, items.length ? lead : ""].filter(Boolean).join("\n\n"),
      suggestions: items,
      detail,
    };
  };

  // Annotate the bucketed picks with a name→ratingBucket map: keep 高/中 (badge),
  // keep未查 (null), DROP Google-bad. Bucket structure/order is preserved.
  const applyFacts = (rbByName: Map<string, string | null>): SuggestionItem[] => {
    const items: SuggestionItem[] = [];
    for (const { c, label } of flat) {
      const has = rbByName.has(cName(c));
      const rb = has ? rbByName.get(cName(c))! : null;
      if (has && rb && rb !== "高" && rb !== "中") continue; // Google says 低 → drop
      items.push(toItem(c, label, rb));
    }
    return items;
  };

  // Cache hit → annotate from cache, no Google/Haiku spend (same-area re-ask is free).
  const cached = cacheGet(key);
  if (cached) {
    const rbByName = new Map<string, string | null>();
    for (const cc of cached) if (!excluded.has(cc.restaurantId)) rbByName.set(cc.name, cc.ratingBucket);
    if (rbByName.size) {
      const items = applyFacts(rbByName);
      if (items.length) return result(items);
    }
  }

  // ③ Phase B — server Google-checks the top 5 + Haiku synth (prose = detail).
  if (ENDPOINT && candidates.length) {
    try {
      const byName = new Map(candidates.map((c) => [cName(c), c]));
      const payload = {
        query,
        tags: [...new Set(candidates.map((c) => c.tag))].slice(0, 6),
        candidates: candidates.map((c) => ({ name: cName(c), addr: c.r.addr, area: c.r.area, tag: c.tag })),
      };
      const res = await fetch(ENDPOINT, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(22000),
      });
      if (res.ok) {
        const data = await res.json();
        const facts: { name: string; ratingBucket: string | null; placeId?: string }[] = Array.isArray(data.facts) ? data.facts : [];
        if (facts.length) {
          cacheSet(key, facts.filter((f) => f.placeId && byName.has(f.name)).map((f) => {
            const c = byName.get(f.name)!;
            return { restaurantId: c.r.id, name: f.name, area: c.r.area, tag: c.tag, ratingBucket: f.ratingBucket, placeId: f.placeId! };
          }));
        }
        const rbByName = new Map<string, string | null>();
        for (const f of facts) if (byName.has(f.name)) rbByName.set(f.name, f.ratingBucket);
        const items = applyFacts(rbByName);
        if (items.length) {
          const detail = typeof data.text === "string" && data.text.trim() ? data.text.trim() : undefined;
          return result(items, detail);
        }
      }
    } catch { /* fall through to Phase A */ }
  }

  // ④ Phase A fallback — taste-matched names (「未查評價」), still clickable cards.
  return result(flat.map(({ c, label }) => toItem(c, label)));
}
