// Reads the pre-cached「知名店」per hot area (server/famous-batch.mjs output).
// Values are FEHD ids only — names/data come from the app's FEHD catalogue, so a
// user pick is 0 Google calls and links straight to the detail page.
let cache: Record<string, string[]> | null = null;

export async function loadFamous(baseUrl: string): Promise<void> {
  if (cache) return;
  try {
    const res = await fetch(`${baseUrl}data/famous.json`);
    const d = await res.json();
    cache = (d && d.areas) || {};
  } catch {
    cache = {};
  }
}

/** FEHD ids of the prominent stores for a colloquial area (empty if none). */
export function famousFor(area: string): string[] {
  return cache?.[area] ?? [];
}
