// Squeeze the FEHD facts we already have into user-facing detail — NO external
// fetch, NO AI, NO review text. Everything here is derived purely from the FEHD
// open-data fields (type / district / facility codes / licence expiry).
import type { Restaurant } from "./types";

// FEHD INFO codes → { icon, tag (short chip), phrase (for a sentence) }.
export const FACILITY: Record<string, { icon: string; tag: string; phrase: string }> = {
  A: { icon: "🌳", tag: "戶外座位", phrase: "有戶外座位" },
  B: { icon: "🎤", tag: "卡拉OK", phrase: "設卡拉OK" },
  C: { icon: "🎤", tag: "卡拉OK", phrase: "設卡拉OK" },
  D: { icon: "✅", tag: "ISO食安", phrase: "有 ISO 22000 食安認證" },
  E: { icon: "🥩", tag: "生肉", phrase: "可提供生食肉類" },
  F: { icon: "🦪", tag: "生蠔", phrase: "可提供生蠔" },
  G: { icon: "🍣", tag: "刺身", phrase: "可提供刺身" },
  H: { icon: "🍣", tag: "壽司", phrase: "可提供壽司" },
};

const TYPE_ZH: Record<string, string> = { RL: "食肆", RR: "小食店", MR: "海鮮舫" };
export function typeZh(code: string): string {
  return TYPE_ZH[code] ?? "食肆";
}

// English FEHD district → Chinese, for a natural-reading sentence.
const DISTRICT_ZH: Record<string, string> = {
  Eastern: "東區", "Wan Chai": "灣仔區", Southern: "南區", "Central/Western": "中西區",
  Islands: "離島區", "Kwun Tong": "觀塘區", "Kowloon City": "九龍城區",
  "Wong Tai Sin": "黃大仙區", "Yau Tsim": "油尖區", "Mong Kok": "旺角區",
  "Sham Shui Po": "深水埗區", "Kwai Tsing": "葵青區", "Tsuen Wan": "荃灣區",
  "Tuen Mun": "屯門區", "Yuen Long": "元朗區", "Tai Po": "大埔區", North: "北區",
  "Sha Tin": "沙田區", "Sai Kung": "西貢區", "Food Truck": "美食車",
};
export function districtZh(area: string): string {
  return DISTRICT_ZH[area] ?? area;
}

/** Deduped facility chips for a restaurant (icon + short tag). */
export function facilitiesOf(r: Restaurant): { code: string; icon: string; tag: string }[] {
  const seen = new Set<string>();
  const out: { code: string; icon: string; tag: string }[] = [];
  for (const code of r.info ?? []) {
    const f = FACILITY[code];
    if (!f || seen.has(f.tag)) continue;
    seen.add(f.tag);
    out.push({ code, icon: f.icon, tag: f.tag });
  }
  return out;
}

/** Neutral one-line intro, built ONLY from FEHD facts (zero-AI, zero-spend).
 *  NOTE: facility codes are LICENCE permissions (not actual supply), so they are
 *  NOT stated here as「可提供 X」— they live in a clearly-labelled licence block. */
export function introLine(r: Restaurant): string {
  return `${districtZh(r.area)}${typeZh(r.type)}。`;
}

/** Casual "occasion" tags derived from FEHD type + facility codes (neutral). */
export function occasionTags(r: Restaurant): string[] {
  const t: string[] = [];
  if (r.type === "MR") t.push("聚會");
  if (r.type === "RR") t.push("快食");
  if (r.info?.includes("A")) t.push("戶外座位");
  if (r.info?.includes("B") || r.info?.includes("C")) t.push("聚會・K房");
  if (!t.length) t.push("坐低慢慢食");
  return [...new Set(t)].slice(0, 3);
}

/** "持牌至 2027-06-30" — a light trust signal, only when we have the date. */
export function expiryLabel(r: Restaurant): string | null {
  return r.exp ? `持牌至 ${r.exp}` : null;
}
