// Encrypted on-device photo store (§5.3). Photos are downscaled, encrypted with
// AES-GCM, and kept in IndexedDB — NEVER uploaded. The user owns them and can
// delete (deleting a memory deletes its photo; the settings wipe clears all).
//
// The AES key lives in localStorage on THIS device only. That protects data at
// rest within the app's storage, not against someone who already controls the
// unlocked device — a real release would bind the key to device auth / secure
// enclave. Honest encryption-at-rest for the mock tester build.

const DB = "dm-photos";
const STORE = "photos";
const KEY_LS = "dm.photokey";
const MAX_DIM = 1024;

// ---- AES-GCM key (per device) ----------------------------------------------

let keyPromise: Promise<CryptoKey> | null = null;
function getKey(): Promise<CryptoKey> {
  if (keyPromise) return keyPromise;
  keyPromise = (async () => {
    const stored = localStorage.getItem(KEY_LS);
    if (stored) {
      return crypto.subtle.importKey("jwk", JSON.parse(stored), { name: "AES-GCM" }, true, [
        "encrypt",
        "decrypt",
      ]);
    }
    const key = await crypto.subtle.generateKey({ name: "AES-GCM", length: 256 }, true, [
      "encrypt",
      "decrypt",
    ]);
    const jwk = await crypto.subtle.exportKey("jwk", key);
    localStorage.setItem(KEY_LS, JSON.stringify(jwk));
    return key;
  })();
  return keyPromise;
}

// ---- IndexedDB ------------------------------------------------------------

function idb(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB, 1);
    req.onupgradeneeded = () => {
      if (!req.result.objectStoreNames.contains(STORE)) req.result.createObjectStore(STORE);
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

async function tx<T>(mode: IDBTransactionMode, fn: (s: IDBObjectStore) => IDBRequest): Promise<T> {
  const db = await idb();
  return new Promise<T>((resolve, reject) => {
    const t = db.transaction(STORE, mode);
    const req = fn(t.objectStore(STORE));
    req.onsuccess = () => resolve(req.result as T);
    req.onerror = () => reject(req.error);
  });
}

// ---- downscale ------------------------------------------------------------

async function downscale(file: File): Promise<ArrayBuffer> {
  try {
    const bmp = await createImageBitmap(file);
    const scale = Math.min(1, MAX_DIM / Math.max(bmp.width, bmp.height));
    const w = Math.max(1, Math.round(bmp.width * scale));
    const h = Math.max(1, Math.round(bmp.height * scale));
    const canvas = document.createElement("canvas");
    canvas.width = w;
    canvas.height = h;
    canvas.getContext("2d")!.drawImage(bmp, 0, 0, w, h);
    bmp.close?.();
    const blob: Blob | null = await new Promise((r) => canvas.toBlob(r, "image/jpeg", 0.8));
    if (blob) return blob.arrayBuffer();
  } catch {
    /* fall through to raw bytes */
  }
  return file.arrayBuffer();
}

// ---- public API -----------------------------------------------------------

function uid(): string {
  return crypto.randomUUID
    ? crypto.randomUUID()
    : "p-" + Math.random().toString(36).slice(2) + Date.now().toString(36);
}

/** Encrypt + store a photo; returns its id (or null if storage failed). */
export async function putPhoto(file: File): Promise<string | null> {
  try {
    const plain = await downscale(file);
    const key = await getKey();
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const ct = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, plain);
    const id = uid();
    await tx("readwrite", (s) => s.put({ iv, ct, type: "image/jpeg" }, id));
    return id;
  } catch {
    return null;
  }
}

/** Decrypt a stored photo into an object URL (caller revokes), or null. */
export async function getPhotoUrl(id: string): Promise<string | null> {
  try {
    const rec = await tx<{ iv: BufferSource; ct: BufferSource; type: string } | undefined>(
      "readonly",
      (s) => s.get(id)
    );
    if (!rec) return null;
    const key = await getKey();
    const plain = await crypto.subtle.decrypt({ name: "AES-GCM", iv: rec.iv }, key, rec.ct);
    return URL.createObjectURL(new Blob([plain], { type: rec.type }));
  } catch {
    return null;
  }
}

export async function delPhoto(id: string): Promise<void> {
  try {
    await tx("readwrite", (s) => s.delete(id));
  } catch {
    /* ignore */
  }
}

export async function clearPhotos(): Promise<void> {
  try {
    await tx("readwrite", (s) => s.clear());
  } catch {
    /* ignore */
  }
}
